\begin{ex}%[2D1N1-2]
 Cho hàm số $f(x) = \dfrac{1}{x} + \dfrac{1}{\cos ^2 x}$. Chọn khẳng định đúng.
 \choice
 {\True $\displaystyle\int f(x) \mathrm{\,d}x = \ln |x| + \tan x + C$}
 {$\displaystyle\int f(x) \mathrm{\,d}x = \ln x + \tan x + C$}
 {$\displaystyle\int f(x) \mathrm{\,d}x = \ln x + \tan |x| + C$}
 {$\displaystyle\int f(x) \mathrm{\,d}x = \ln |x| + \tan x$} 
 \loigiai{
 Ta có $\displaystyle\int \left(\dfrac{1}{x} + \dfrac{1}{\cos ^2 x}\right) \mathrm{\,d}x = \displaystyle\int \dfrac{1}{x} \mathrm{\,d}x + \displaystyle\int \dfrac{1}{\cos ^2 x} \mathrm{\,d}x = \ln |x| + \tan x + C$.
 }
\end{ex}

