\begin{ex}%[2D1H1-2]
	\immini[thm]{Cho hàm số $y=f(x)=\dfrac{x^2+bx+c}{x-2}$ có đạo hàm $f'(x)$. Đồ thị của hàm số $f'(x)$ như hình vẽ bên.
		\choiceTF
			{\True Phương trình $f'(x)=0$ có hai nghiệm $x=1$ và $x=3$}
			{Hàm số $y=f(x)$ nghịch biến trên khoảng $(1;3)$}
			{\True Hàm số $y=f(x)$ đạt cực đại tại $x=1$ và đạt cực tiểu tại $x=3$}
			{\True Nếu $f(0)=1$ thì $\max\limits_{[3;4]} f(x)=6$}}
	{\begin{tikzpicture}[line cap=butt,line join=miter,>=stealth,font=\normalsize,scale=.5]
		\tikzset{declare function={xmin=-2;xmax=6;ymin=-3;ymax=2.5;
				f(\x)=((\x)^2-4*(\x)+3)/((\x)-2)^2;
			},
			smooth,samples=450
		}
		\draw[->] (xmin,0)--(xmax,0) node[shift={(-100:7pt)}]{$ x $};
		\draw[->] (0,ymin)--(0,ymax) node[shift={(190:7pt)}]{$ y $};
		\fill (0,0) node[shift={(225:10pt)}]{$ O $};
		\draw (1,0) circle(1pt)node[below left]{$1$}
		(3,0) circle(1pt)node[below right]{$3$};
		\clip (xmin,ymin) rectangle (xmax,ymax);
		\draw  plot[domain=xmin:2-.1] (\x, {f(\x)});
		\draw  plot[domain=2+.1:xmax] (\x, {f(\x)});
	\end{tikzpicture}}
\loigiai{
	Tập xác định $\mathscr{D}=\mathbb{R} \setminus \{2\}$.
	\begin{itemchoice}
		\itemch Dựa vào đồ thị ta thấy $f'(x)=0$ có hai nghiệm $x=1$ và $x=3$.
		\itemch Ta có $f'(x)=\dfrac{x^2-4x-2b-c}{(x-2)^2}=0\Leftrightarrow \hoac{&x=1\\&x=3.}$\\
		Bảng xét dấu
		\begin{center}
			\begin{tikzpicture}[>=stealth]
				\tkzTabInit[nocadre=false,lgt=1.5,espcl=2,deltacl=0.6]{$x$/.7 ,$f'(x)$/.7}
				{$-\infty$ , $1$ , $2$ , $3$ , $+\infty$}
				\tkzTabLine{ , + , $0$ , - , d, -, $0$ , + , }
			\end{tikzpicture}
		\end{center}
		Vậy hàm số $y=f(x)$ nghịch biến trên các khoảng $(1;2)$ và $(2;3)$.
		\itemch Dựa vào bảng xét dấu ta thấy hàm số $y=f(x)$ đạt cực đại tại $x=1$ và đạt cực tiểu tại $x=3$.
		\itemch Nếu $f(0)=1$ thì $\dfrac{c}{-2}=1\Rightarrow c=-2$. \\
		Mà $f'(1)=0\Rightarrow 1-4-2b+2=0\Rightarrow b=-\dfrac{1}{2}$. Khi đó $f(x)=\dfrac{x^2-\dfrac{1}{2}x-2}{x-2}$. \\
		Mà hàm số $y=f(x)$ đồng biến trên đoạn $[3;4]$ nên $\max\limits_{[3;4]} f(x)=f(4)=6$.
	\end{itemchoice}
}
\end{ex}

\begin{ex}%[2D1H1-5]
	Một vật chuyển động thẳng được cho bởi phương trình $s(t)=-\dfrac{1}{3}t^3+4t^2+9t$, trong đó $t$ tính bằng giây và $s(t)$ là vị trí của vật tại thời điểm $t$, tính bằng mét.
	\choiceTF
		{Vận tốc của vật tại các thời điểm $t=3$ giây là $v(3)=1 \text{ m/s}$}
		{\True Quãng đường vật đi được từ lúc bắt đầu chuyển động đến khi vật đứng yên là $162 \text{ m}$}
		{\True Gia tốc của vật tại thời điểm $t=3$ giây là $a(3)=2 \text{ m/s}^2$}
		{\True Vật tăng tốc khi $t \in[0; 4]$}
	\loigiai
	{
		Biểu thức vận tốc tức thời của vật là $v(t)=-t^2+8t+9$.\\
		Vận tốc của vật tại các thời điểm $t=3$ giây là $v(3)=-3^2+8\cdot 3+9=24 \text{ (m/s)}$.\\
		Vật đứng yên khi
		\[v(t)=0\Leftrightarrow -t^2+8t+9=0\Leftrightarrow \left[\begin{aligned}&t=-1 \,(\text{không thỏa mãn}) \\&t=9 \,(\text{thỏa mãn}).\end{aligned}\right.\]
		Trong khoảng thời gian từ lúc vật bắt đầu chuyển động đến khi vật đứng yên thì vật không đổi chiều chuyển động.\\
		Ta có $s(0)=0$ và $s(9)=-\dfrac{1}{3}\cdot 9^3+4\cdot 9^2+9\cdot 9=162 \text{ (m)}$.\\
		Quãng đường vật đi được từ lúc bắt đầu chuyển động đến thời điểm $t=9$ giây là $\left|s(9)-s(0)\right|=162 \text{ (m)}$.\\
		Biểu thức gia tốc tức thời của vật là $a(t)=v'(t)=-2t+8$.\\
		Gia tốc của vật tại thời điểm $t=3$ giây là $a(3)=-2\cdot 3+8=2\, \left(\text{m/s}^2\right)$.\\
		Phương trình $v'(t)=0$ có nghiệm $t=4$.\\
		Bảng biến thiên của $v(t)$ trên nửa khoảng $[0;+\infty)$\\
		\centerline
		{
			\begin{tikzpicture}[yscale=.6,xscale=1.5, kxd/.pic={\draw[double distance=1pt] (90:.3)--(-90:.3);}]
				\path (0,0) node{$t$} ++(0:1) node[left=-.2]{$0$} ++(0:3) node{$4$} ++(0:3) node[right=-.2]{$+\infty$}
				(0,-1) node{$v'(t)$} ++(0:2.5) node{$+$} ++(0:1.5) node{$0$} ++(0:1.5) node{$-$}
				(0,-3.5) coordinate(a) node{$v(t)$}
				(1,-4.2) node[left=-.2] (A) {$9$} (4,-2) node (B) {$25$} (7,-5) node[right=-.2] (C) {$-\infty$};
				\foreach \d/\dd in {A/B, B/C} \draw[-latex] ([shift={(45:.2)}]\d) -- ([shift={(-135:.2)}]\dd);
				\begin{scope}[shift={(-.5,.5)}]
					\draw (0,0) rectangle +(8,-6) (0,-1)--+(0:8) (0,-2)--+(0:8) (1,0)--+(-90:6);
				\end{scope}
			\end{tikzpicture}
		}
		Dựa vào bảng biến thiên trên, vật tăng tốc khi $t \in[0; 4]$.
		\begin{itemchoice}
			\itemch Vận tốc của vật tại các thời điểm $t=3$ giây là $v(3)=-3^2+8\cdot 3+9=24 \text{ (m/s)}$.
			\itemch Quãng đường vật đi được từ lúc bắt đầu chuyển động đến thời điểm $t=9$ giây là $\left|s(9)-s(0)\right|=162 \text{ (m)}$.
			\itemch Gia tốc của vật tại thời điểm $t=3$ giây là $a(3)=-2\cdot 3+8=2\, \left(\text{m/s}^2\right)$.
			\itemch Vật tăng tốc khi $t \in[0; 4]$.
		\end{itemchoice}
	}
\end{ex}

\begin{ex}%[2D1H1-1]
 Cho hàm số $y=\sqrt{1-x^2}$. Gọi $(a;b)$ là khoảng đồng biến có độ dài lớn nhất của hàm số trên. Tính $a+b$.

 \shortans{-1}
 \loigiai{
 Tập xác định $\mathscr{D}=[-1;1]$.\\
 Ta có $y'=\dfrac{-x}{\sqrt{1-x^2}}$ suy ra $y'>0$ khi $x<0$.\\
 Kết hợp với tập xác định, ta có khoảng đồng biến có độ dài lớn nhất là khoảng $(-1;0)$.\\
 Từ đó, ta có $a=-1$, $b=0$ suy ra $a+b=-1$.}
\end{ex}

\begin{ex}%[2D1H1-1]
	Hàm số $y=\log_2(x^2+3x)$ nghịch biến trên khoảng $(-\infty; a)$. Giá trị lớn nhất của $a$ là bao nhiêu?
	\par\shortans[0]{-3}
	\loigiai{
		Hàm số xác định khi $x^2+3x>0\Leftrightarrow \hoac{&x>0\\ &x<-3.}$\\
		Tập xác định $\mathscr{D}=(-\infty;-3)\cup(0;+\infty)$.\\
		Đạo hàm $y'=\dfrac{2x+3}{(x^2+3x)\ln 2}$.\\
		Hàm số nghịch biến khi $y'<0\Rightarrow 2x+3<0\Leftrightarrow x<-\dfrac{3}{2}$.\\
		Kết hợp điều kiện xác định, hàm số nghịch biến trên khoảng $(-\infty;-3)$.\\
		Vậy giá trị lớn nhất của $a$ là $-3$.
	}
\end{ex}

\begin{ex}%[2D1H1-5]
	[Trích đề ôn tập HKI-Lớp 12-THPT Bùi Thị Xuân-Năm học 2024-2025]
	Một vật đang đứng yên thì bắt đầu chuyển động theo quy luật $s(t)=-t^3+3t^2+6t$, với $t$ (giây) là khoảng thời gian tính từ lúc vật bắt đầu chuyển động và $s$ (mét) là quãng đường vật đi được trong khoảng thời gian đó. Hỏi vật tăng tốc trong khoảng thời gian bao nhiêu giây tính từ lúc bắt đầu chuyển động?
	\loigiai{Vận tốc của vật là $v(t)=s'(t)=-3t^2+6t+6$.\\
		Ta có $v'(t)=-6t+6$.\\
		Cho $v'(t)=0\Leftrightarrow t=1$.\\
		Bảng biến thiên\\
		\begin{center}
			\begin{tikzpicture}
				\tkzTabInit[lgt=1.2,espcl=2.5,deltacl=0.6]
				{$t$/0.6,$v'(t)$/0.6,$v(t)$/2}{$0$,$1$,$+\infty$}
				\tkzTabLine{,+,0,-,}
				\tkzTabVar{-/$6$,+/$9$,-/$-\infty$}
			\end{tikzpicture}
		\end{center}
		Dựa vào bảng biến thiên, ta thấy $v(t)$ tăng khi $t\in (0;1)$. Vậy vật tăng tốc trong khoảng thời gian từ gian $1$ giây tính từ lúc bắt đầu chuyển động.
	}
\end{ex}

\begin{ex}%[2D1H1-5]
	Sau khi phát hiện một bệnh dịch, các chuyên gia y tế ước tính số người nhiễm bệnh kể từ ngày xuất hiện bệnh nhân đầu tiên đến ngày thứ $t$ là $f(t)=45t^2-t^3$, $ t=0$, $1$, $2$, $\ldots$, $25$. Nếu coi $f(t)$ là hàm số xác định trên đoạn $[0; 25]$ thì đạo hàm $f'(t)$ được xem là tốc độ truyền bệnh (người/ngày) tại thời điểm $t$. Giả sử khoảng thời gian mà tốc độ truyền bệnh giảm là từ ngày thứ $m$ đến ngày thứ $n$. Khi đó $n-m$ bằng bao nhiêu?
	\loigiai{
		Tốc độ truyền bệnh $y=f'(t)=-3t^2+90t$ với $t\in [0; 25]$.\\
		Ta có $y'=-6t+90$; $y'=0\Leftrightarrow t=15$.\\
		Bảng biến thiên
		\begin{center}
			\begin{tikzpicture}[>=stealth,font=\footnotesize,scale=1]
				\tkzTabInit[nocadre=false,lgt=1.2,espcl=3,deltacl=.55]{$x$ /1, $y'$ /1, $y$ /2}{$0$, $15$, $25$}
				\tkzTabLine{, +, 0, -, }
				\tkzTabVar{-/ $0$,+/$675$,-/$375$}
			\end{tikzpicture}
		\end{center}
		Tốc độ truyền bệnh giảm từ ngày $15$ đến ngày $25$.\\
		Do đó $m=15$, $n=25$.\\ Suy ra $m-n=10$.
	}
\end{ex}

